// Time:  O(n)
// Space: O(1)

// array
class Solution {
public:
    int lateFee(vector<int>& daysLate) {
        return accumulate(cbegin(daysLate), cend(daysLate), 0, [](const auto& total, const auto& x) {
            return total + (x == 1 ? x : (x >= 6 ? 3 * x : 2 * x));
        });
    }
};

# Time:  O(n)
# Space: O(1)

# array
class Solution(object):
    def lateFee(self, daysLate):
        """
        :type daysLate: List[int]
        :rtype: int
        """
        return sum(1 if i == 1 else 3*i if i >= 6 else 2*i for i in daysLate)
